1	const PROCESSING_FEE = 5;
2	const BASE_PREMIUM_PER_ITEM = 25;
3	const BLOCK_OF_THREE_DISCOUNT = 15;
4	const BLOCK_SIZE = 3;
5	
6	type Scenario = { steps: { op: string; items: { type: string }[] }[] };
7	
8	function countItemsByType(items: { type: string }[]): Map<string, number> {
9	  const counts = new Map<string, number>();
10	  for (const item of items) {
11	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
12	  }
13	  return counts;
14	}
15	
16	function basePremiumForGroup(count: number): number {
17	  const subtotal = count * BASE_PREMIUM_PER_ITEM;
18	  const discount = count === BLOCK_SIZE ? BLOCK_OF_THREE_DISCOUNT : 0;
19	  return subtotal - discount;
20	}
21	
22	export function runScenario(scenario: unknown): unknown {
23	  const items = (scenario as Scenario).steps[0].items;
24	  const itemCountsByType = countItemsByType(items);
25	  let basePremium = 0;
26	  for (const count of itemCountsByType.values()) {
27	    basePremium += basePremiumForGroup(count);
28	  }
29	  return { results: [{ premium: basePremium + PROCESSING_FEE }] };
30	}
